INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (1, 'Bug', 'App crashes on adding expense', 'The app crashes whenever I try to add a new expense above 10,000.', 2, 'Open', 1, NULL, '2025-01-05 10:15:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (2, 'Feature', 'Add dark mode', 'It would be great to have a dark mode for using the app at night.', 5, 'Open', 2, NULL, '2025-01-06 09:20:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (3, 'Bug', 'Incorrect total in dashboard', 'The total expense in dashboard does not match the sum of listed expenses.', 3, 'In Progress', 3, NULL, '2025-01-07 14:32:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (4, 'Design', 'Improve category icons', 'Category icons are too similar and confusing at a glance.', 4, 'Open', 4, NULL, '2025-01-08 18:45:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (5, 'Performance', 'Slow loading of reports', 'Reports page takes more than 10 seconds to load with many records.', 3, 'Open', 5, NULL, '2025-01-09 08:10:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (6, 'Bug', 'Date filter not working', 'Filtering expenses by date range returns incomplete results.', 2, 'Open', 6, NULL, '2025-01-10 11:05:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (7, 'Feature', 'Support multiple currencies', 'Please allow tracking expenses in different currencies per account.', 5, 'Open', 7, NULL, '2025-01-11 16:50:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (8, 'Bug', 'Cannot delete category', 'Deleting an unused category shows an unknown error.', 3, 'Open', 8, NULL, '2025-01-12 19:25:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (9, 'Design', 'Larger fonts on small devices', 'The font size is too small on my phone, hard to read.', 4, 'Open', 9, NULL, '2025-01-13 07:40:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (10, 'Performance', 'Lag when scrolling expense list', 'The expense list becomes laggy when more than 500 records exist.', 3, 'Open', 10, NULL, '2025-01-14 12:30:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (11, 'Feature', 'Export to Excel', 'Kindly add an option to export expenses and budgets to Excel.', 5, 'Open', 1, NULL, '2025-01-15 09:15:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (12, 'Bug', 'Duplicate expenses after sync', 'After syncing, some expenses appear twice in the list.', 2, 'Open', 2, NULL, '2025-01-16 13:05:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (13, 'Design', 'Show account name in expense list', 'Please show account name beside each expense for clarity.', 4, 'Open', 3, NULL, '2025-01-17 17:45:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (14, 'Feature', 'Add reminders for bills', 'Would like reminders for recurring bills like rent and utilities.', 5, 'Open', 4, NULL, '2025-01-18 20:00:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (15, 'Bug', 'Cannot login after password reset', 'After resetting my password, the app shows invalid credentials.', 1, 'Open', 5, NULL, '2025-01-19 10:25:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (16, 'Performance', 'High battery usage', 'The app drains battery quickly when left open on dashboard.', 2, 'Open', 6, NULL, '2025-01-20 08:55:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (17, 'Feature', 'Family sharing', 'Please add ability to share budgets and expenses with family members.', 5, 'Open', 7, NULL, '2025-01-21 15:20:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (18, 'Bug', 'Wrong currency symbol in reports', 'Reports show INR symbol even when account currency is USD.', 3, 'Open', 8, NULL, '2025-01-22 18:40:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (19, 'Design', 'Better color coding', 'Use clearer colors to differentiate income, expense and transfer.', 4, 'Open', 9, NULL, '2025-01-23 07:35:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (20, 'Feature', 'Attach receipts to expenses', 'I want to upload photo of bill/receipt with each expense.', 5, 'Open', 10, NULL, '2025-01-24 11:50:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (21, 'Bug', 'Categories not saving', 'Newly added categories disappear after app restart.', 2, 'In Progress', 1, NULL, '2025-01-25 09:45:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (22, 'Performance', 'Slow first-time startup', 'The app takes too long to open the first time after install.', 3, 'Open', 2, NULL, '2025-01-26 13:30:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (23, 'Design', 'Show monthly summary chart', 'A simple bar chart on dashboard for monthly totals would help.', 5, 'Open', 3, NULL, '2025-01-27 16:05:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (24, 'Feature', 'Biometric login', 'Allow fingerprint or face ID login for faster access.', 5, 'Open', 4, NULL, '2025-01-28 19:55:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (25, 'Bug', 'Incorrect sorting by date', 'Sorting by date puts some older entries at the top.', 2, 'Open', 5, NULL, '2025-01-29 08:20:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (26, 'Feature', 'Custom categories per user', 'Each family member should be able to maintain their own categories.', 4, 'Open', 6, NULL, '2025-01-30 14:15:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (27, 'Design', 'Highlight today’s expenses', 'Highlight entries for today with a subtle background color.', 4, 'Open', 7, NULL, '2025-01-31 18:10:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (28, 'Bug', 'Report filters reset randomly', 'Report filters reset when navigating back from details.', 3, 'Open', 8, NULL, '2025-02-01 09:05:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (29, 'Feature', 'Offline mode', 'Allow adding expenses offline and sync when internet is back.', 5, 'Open', 9, NULL, '2025-02-02 12:40:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (30, 'Performance', 'Search is very slow', 'Searching for text in expenses takes several seconds.', 2, 'Open', 10, NULL, '2025-02-03 10:10:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (31, 'Bug', 'Negative balance not allowed', 'Transfers between accounts sometimes create negative balances.', 2, 'In Progress', 1, NULL, '2025-02-04 15:55:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (32, 'Feature', 'Multi-language support', 'Please add support for Hindi and Arabic languages.', 5, 'Open', 2, NULL, '2025-02-05 19:30:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (33, 'Design', 'More compact list view', 'Allow a dense mode to see more rows on one screen.', 4, 'Open', 3, NULL, '2025-02-06 07:50:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (34, 'Bug', 'Export CSV encoding issue', 'Exported CSV opens with garbled characters in Excel.', 3, 'Open', 4, NULL, '2025-02-07 11:25:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (35, 'Feature', 'Goal-based saving', 'Feature to set savings goals and track progress.', 5, 'Open', 5, NULL, '2025-02-08 16:45:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (36, 'Performance', 'Charts take time to render', 'Analytics charts take too long to load with big datasets.', 3, 'Open', 6, NULL, '2025-02-09 20:05:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (37, 'Bug', 'Notification toggle not working', 'Disabling notifications has no effect, still getting alerts.', 2, 'Open', 7, NULL, '2025-02-10 09:35:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (38, 'Design', 'Clearer error messages', 'Error messages should be more specific instead of generic.', 4, 'Open', 8, NULL, '2025-02-11 13:15:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (39, 'Feature', 'Tag-based filtering', 'Allow adding tags to expenses and filter by multiple tags.', 5, 'Open', 9, NULL, '2025-02-12 17:50:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (40, 'Bug', 'Duplicated notifications', 'Getting the same reminder notification multiple times.', 2, 'Open', 10, NULL, '2025-02-13 08:05:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (41, 'Performance', 'Slow sync on mobile data', 'Sync is very slow when using mobile data compared to Wi-Fi.', 3, 'Open', 1, NULL, '2025-02-14 10:45:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (42, 'Feature', 'Archive old accounts', 'Ability to archive accounts that are no longer used.', 4, 'Open', 2, NULL, '2025-02-15 14:25:00', '2025-12-07 09:04:48.528242');
INSERT INTO public.feedbacks (id, issue_type, subject, description, rating, status, user_id, reply, created_at, updated_at) VALUES (43, 'Design', 'Better empty state screens', 'Show tips and help text when there is no data yet.', 4, 'Open', 3, NULL, '2025-02-16 18:30:00', '2025-12-07 09:04:48.528242');
